function WeddingServices() {
  const weddingHelpers = [
    {
      name: "Lina Events",
      service: "Wedding Planning",
      experience: "6 Years",
      contact: "lina.events@email.com",
      price: "$1500 package",
      image: "https://cdn-icons-png.flaticon.com/512/3048/3048122.png",
    },

    {
      name: "Maya Studio",
      service: "Wedding Photography",
      experience: "5 Years",
      contact: "maya.photo@email.com",
      price: "$1200 package",
      image: "https://cdn-icons-png.flaticon.com/512/2922/2922510.png",
    },

    {
      name: "Nour Beauty",
      service: "Bridal Makeup",
      experience: "4 Years",
      contact: "nour.makeup@email.com",
      price: "$300 session",
      image: "https://cdn-icons-png.flaticon.com/512/4140/4140048.png",
    },

    {
      name: "White Flowers",
      service: "Wedding Decoration",
      experience: "7 Years",
      contact: "flowers@email.com",
      price: "$2000 decoration package",
      image: "https://cdn-icons-png.flaticon.com/512/3468/3468377.png",
    },

    {
      name: "Golden Cake",
      service: "Wedding Cake Design",
      experience: "3 Years",
      contact: "cake@email.com",
      price: "$500 cake package",
      image: "https://cdn-icons-png.flaticon.com/512/3075/3075977.png",
    },

    {
      name: "DJ Karim",
      service: "Wedding Music and DJ",
      experience: "8 Years",
      contact: "djkarim@email.com",
      price: "$700 event",
      image: "https://cdn-icons-png.flaticon.com/512/3659/3659898.png",
    },
  ];

  function requestService(name) {
    alert("Your request has been sent to " + name);
  }

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Wedding Services</h1>

        <p>
          Discover wedding professionals for planning, photography,
          makeup, decoration, cakes, and entertainment services.
        </p>
      </div>

      <section className="cards">
        {weddingHelpers.map((helper, index) => (
          <div className="card" key={index}>
            <img
              src={helper.image}
              alt={helper.name}
              className="service-image"
            />

            <h3>{helper.name}</h3>

            <p>
              <strong>Service:</strong> {helper.service}
            </p>

            <p>
              <strong>Experience:</strong> {helper.experience}
            </p>

            <p>
              <strong>Email:</strong> {helper.contact}
            </p>

            <p>
              <strong>Price:</strong> {helper.price}
            </p>

            <button
              className="request-btn"
              onClick={() => requestService(helper.name)}
            >
              Request Service
            </button>
          </div>
        ))}
      </section>
    </section>
  );
}

export default WeddingServices;
